import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as c,o,c as t,a as e,b as i,d,e as s}from"./app-d73ff56b.js";const l={},r=s("<p>현재 프로젝트 레포지토리의 디렉터리 구조는 이렇게 되어있다.</p><blockquote><p>📁 toeic<br> ├─ 📁 backend/<br> ├─ 📁 frontend/<br> ├─ package-lock.json<br> └─ package.json</p></blockquote><p>GitHub 레포지토리에서 frontend 디렉터리를 제외한 나머지 파일 및 디렉터리를 clone해서 가져오려면 어떻게 해야할까?</p><p>ec2 인스턴스에 서버의 포함된 패키지와 클라이언트에 포함된 패키지까지 설치하면<br> 서버를 구동하는데 불필요한 패키지까지 설치해야하므로 그만큼 효율적이지 못하다.</p><p>그래서 frontend 디렉터리를 제외한 나머지만 clone을 해보려고한다.<br> git에서는 sparse checkout이라는 기능을 제공해 일부 디렉터리만 clone할 수 있도록 지원하고있다.</p>",5),p={href:"https://git-scm.com/docs/git-sparse-checkout",target:"_blank",rel:"noopener noreferrer"},u=s(`<p>git 버전 2.35이상 부터는 <code>sparse-checkout</code>이라는 명령어로 설정할 수 있다.<br><code>sparse-checkout</code> 명령어가 나왔을 당시에는 <code>init</code>과 <code>set</code>을 모두 호출해야했지만<br> 현재는 <code>set</code>으로 <code>sparse-checkout</code>을 바로 설정할 수 있다.</p><h2 id="git-레포지토리-초기-설정" tabindex="-1"><a class="header-anchor" href="#git-레포지토리-초기-설정" aria-hidden="true">#</a> git 레포지토리 초기 설정</h2><p>이미 존재하는 프로젝트를 clone하는 것이므로 프로젝트 이름의 폴더를 만들어서 진행한다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> toeic
<span class="token builtin class-name">cd</span> toeic
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>그리고 해당 폴더에서 git을 시작하고 pull하기전에 clone할 레포지토리 URL을 연결해야한다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> init
<span class="token function">git</span> remote <span class="token function">add</span> origin <span class="token operator">&lt;</span>project-url<span class="token operator">&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="필요한-디렉터리만-clone하기" tabindex="-1"><a class="header-anchor" href="#필요한-디렉터리만-clone하기" aria-hidden="true">#</a> 필요한 디렉터리만 clone하기</h2><p>그 다음 sparse-checkout을 설정하자.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> sparse-checkout <span class="token builtin class-name">set</span> <span class="token string">&#39;backend/&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>이렇게 입력하고 git pull을 하게 되면 전체 디렉터리 중 backend 폴더 하위의 내용들만 받아진다.<br> 하지만 나는 toeic 아래에 있는 package.json도 받아오고 싶어서 특정 폴더를 제외하는 설정을 했다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> sparse-checkout <span class="token builtin class-name">set</span> --no-cone <span class="token string">&#39;/*&#39;</span> <span class="token string">&#39;!frontend/&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>clone하기를 원하지 않는 디렉터리는 패턴 앞에 <code>!</code>를 붙여서 제외하면 된다.</p><p>설정이 되어있는지 확인하려면 <code>list</code>를 명령어를 사용한다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/2d628532-aee9-46dd-99a7-b31e2b4ca403" alt="로 적용되었는지 확인" tabindex="0" loading="lazy"><figcaption><code>git sparse-checkout list</code>로 적용되었는지 확인</figcaption></figure><p>여기서 기존 set 설정에서 패턴을 추가하려면 <code>add</code>를 사용하면된다.</p><p>다시 변경사항을 확실하게 적용하려면 <code>reapply</code>를 적용해주자.<br> 그다음 <code>git pull origin main</code>을 해보면 내가 원하는 폴더만 받아진 것을 볼 수 있다.</p><figure><img src="https://github.com/Zamoca42/blog/assets/96982072/bcb75615-ce04-4880-a55e-92f9aa07e878" alt="로 디렉터리 확인" tabindex="0" loading="lazy"><figcaption><code>ls</code>로 디렉터리 확인</figcaption></figure><p>sparse-checkout 설정을 사용하고싶지않다면 <code>disable</code>로 다시 전체 폴더를 받아오게할 수 있다.</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> sparse-checkout disbale
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,19);function g(b,h){const a=c("ExternalLinkIcon");return o(),t("div",null,[r,e("blockquote",null,[e("p",null,[e("a",p,[i("https://git-scm.com/docs/git-sparse-checkout"),d(a)])])]),u])}const v=n(l,[["render",g],["__file","git-sparse-checkout.html.vue"]]);export{v as default};
